//! BlockoutSpec — structured world layout specification.
//!
//! Defines the data model for procedural world generation. The LLM generates
//! high-level parameters (terrain type, region layout, density); procedural
//! systems handle actual geometry.

use bevy::prelude::*;
use serde::{Deserialize, Serialize};

// ---------------------------------------------------------------------------
// Top-level spec
// ---------------------------------------------------------------------------

/// Complete specification for a procedural world blockout.
///
/// Generated by `gen_plan_layout` from a text prompt, consumed by
/// `gen_apply_blockout` to produce a coarse 3D scene.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct BlockoutSpec {
    /// Terrain generation parameters.
    #[serde(default)]
    pub terrain: BlockoutTerrain,
    /// Global layout algorithm and density.
    #[serde(default)]
    pub layout: LayoutParams,
    /// Spatial regions with per-region parameters.
    #[serde(default)]
    pub regions: Vec<RegionDef>,
    /// Paths connecting regions.
    #[serde(default)]
    pub paths: Vec<PathConnection>,
    /// Material/biome palette.
    #[serde(default)]
    pub palette: WorldPalette,
}

// ---------------------------------------------------------------------------
// Terrain
// ---------------------------------------------------------------------------

/// High-level terrain type — mapped to noise parameters internally.
#[derive(Debug, Clone, Copy, Default, PartialEq, Eq, Serialize, Deserialize, Reflect)]
#[serde(rename_all = "snake_case")]
pub enum TerrainType {
    Flat,
    #[default]
    Hills,
    Mountains,
    Canyon,
    Island,
    Plateau,
}

/// Terrain parameters for the blockout.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct BlockoutTerrain {
    /// High-level terrain shape.
    #[serde(default)]
    pub terrain_type: TerrainType,
    /// Height variation intensity (0.0 = flat, 1.0 = extreme).
    #[serde(default = "default_verticality")]
    pub verticality: f32,
    /// Surface roughness (0.0 = smooth, 1.0 = jagged).
    #[serde(default = "default_roughness")]
    pub roughness: f32,
    /// Base elevation offset.
    #[serde(default)]
    pub base_height: f32,
    /// Optional noise seed for determinism.
    #[serde(default)]
    pub noise_seed: Option<u32>,
}

impl Default for BlockoutTerrain {
    fn default() -> Self {
        Self {
            terrain_type: TerrainType::default(),
            verticality: default_verticality(),
            roughness: default_roughness(),
            base_height: 0.0,
            noise_seed: None,
        }
    }
}

fn default_verticality() -> f32 {
    0.5
}
fn default_roughness() -> f32 {
    0.4
}

impl BlockoutTerrain {
    /// Convert to concrete terrain noise parameters.
    pub fn to_terrain_params(&self, world_size: Vec2) -> crate::terrain::TerrainParams {
        let (height_scale, frequency, octaves) = match self.terrain_type {
            TerrainType::Flat => (1.0, 0.01, 1),
            TerrainType::Hills => (20.0, 0.02, 4),
            TerrainType::Mountains => (60.0, 0.008, 6),
            TerrainType::Canyon => (40.0, 0.015, 5),
            TerrainType::Island => (25.0, 0.012, 4),
            TerrainType::Plateau => (15.0, 0.01, 3),
        };

        let noise_type = match self.terrain_type {
            TerrainType::Flat => crate::terrain::NoiseType::Flat,
            _ => crate::terrain::NoiseType::Perlin,
        };

        crate::terrain::TerrainParams {
            size: world_size,
            resolution: 128,
            height_scale: height_scale * self.verticality.max(0.01),
            noise_type,
            noise_octaves: octaves,
            noise_frequency: frequency * (0.5 + self.roughness),
            seed: self.noise_seed,
            material: crate::terrain::TerrainMaterial::Grass,
            position: Vec3::new(0.0, self.base_height, 0.0),
        }
    }
}

// ---------------------------------------------------------------------------
// Layout
// ---------------------------------------------------------------------------

/// Layout algorithm for spatial partitioning.
#[derive(Debug, Clone, Copy, Default, PartialEq, Eq, Serialize, Deserialize, Reflect)]
#[serde(rename_all = "snake_case")]
pub enum LayoutStyle {
    /// BSP tree partitioning — villages, cities, dungeons.
    Structured,
    /// Voronoi + Poisson disk — forests, natural landscapes.
    #[default]
    Organic,
    /// Concentric rings — arenas, temples.
    Radial,
    /// Regular grid — farms, warehouses.
    Grid,
}

/// Global layout parameters.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct LayoutParams {
    /// Spatial partitioning algorithm.
    #[serde(default)]
    pub style: LayoutStyle,
    /// Overall placement density (0.0–1.0).
    #[serde(default = "default_density")]
    pub density: f32,
    /// Layout regularity (0.0 = chaotic, 1.0 = rigid).
    #[serde(default = "default_regularity")]
    pub regularity: f32,
}

impl Default for LayoutParams {
    fn default() -> Self {
        Self {
            style: LayoutStyle::default(),
            density: default_density(),
            regularity: default_regularity(),
        }
    }
}

fn default_density() -> f32 {
    0.5
}
fn default_regularity() -> f32 {
    0.3
}

// ---------------------------------------------------------------------------
// Regions
// ---------------------------------------------------------------------------

/// A spatial region within the blockout.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct RegionDef {
    /// Unique region identifier (e.g., "village_center", "forest_east").
    pub id: String,
    /// Region bounding rectangle.
    #[serde(default)]
    pub bounds: RegionBounds,
    /// Layout style override for this region.
    #[serde(default)]
    pub region_type: LayoutStyle,
    /// Region-level density override (0.0–1.0).
    #[serde(default = "default_density")]
    pub density: f32,
    /// Whether the region should be walkable.
    #[serde(default = "default_true")]
    pub walkable: bool,
    /// Pre-placed hero object slots (landmarks, buildings).
    #[serde(default)]
    pub hero_slots: Vec<HeroSlot>,
    /// Medium-scale element density (0.0–1.0).
    #[serde(default = "default_density")]
    pub medium_density: f32,
    /// Decorative scatter density (0.0–1.0).
    #[serde(default = "default_regularity")]
    pub decorative_density: f32,
}

fn default_true() -> bool {
    true
}

/// Axis-aligned bounding rectangle for a region (XZ plane).
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct RegionBounds {
    /// Center position [x, z].
    #[serde(default)]
    pub center: [f32; 2],
    /// Size [width, depth].
    #[serde(default = "default_bounds_size")]
    pub size: [f32; 2],
}

impl Default for RegionBounds {
    fn default() -> Self {
        Self {
            center: [0.0, 0.0],
            size: default_bounds_size(),
        }
    }
}

fn default_bounds_size() -> [f32; 2] {
    [20.0, 20.0]
}

/// A reserved placement slot for a hero-scale object.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct HeroSlot {
    /// World position [x, y, z].
    #[serde(default)]
    pub position: [f32; 3],
    /// Bounding box size [x, y, z].
    #[serde(default = "default_hero_size")]
    pub size: [f32; 3],
    /// Semantic role (e.g., "landmark", "entrance", "focal_point").
    #[serde(default)]
    pub role: String,
    /// Content hint for the LLM (e.g., "town hall", "ancient tree").
    #[serde(default)]
    pub hint: String,
}

fn default_hero_size() -> [f32; 3] {
    [5.0, 5.0, 5.0]
}

// ---------------------------------------------------------------------------
// Paths
// ---------------------------------------------------------------------------

/// A path connecting two regions.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct PathConnection {
    /// Source region ID.
    pub from: String,
    /// Destination region ID.
    pub to: String,
    /// Path width in meters.
    #[serde(default = "default_path_width")]
    pub width: f32,
    /// Path material style.
    #[serde(default)]
    pub style: PathStyle,
}

/// Visual style for blockout paths.
#[derive(Debug, Clone, Copy, Default, PartialEq, Eq, Serialize, Deserialize, Reflect)]
#[serde(rename_all = "snake_case")]
pub enum PathStyle {
    #[default]
    Dirt,
    Stone,
    Cobblestone,
    Grass,
    Sand,
}

fn default_path_width() -> f32 {
    3.0
}

// ---------------------------------------------------------------------------
// Palette
// ---------------------------------------------------------------------------

/// World material and style palette.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct WorldPalette {
    /// Primary biome preset.
    #[serde(default)]
    pub primary_biome: Biome,
    /// Accent elements for variety.
    #[serde(default)]
    pub accent_elements: Vec<String>,
    /// Time of day (0.0 = midnight, 0.5 = noon, 1.0 = midnight).
    #[serde(default = "default_time_of_day")]
    pub time_of_day: f32,
}

impl Default for WorldPalette {
    fn default() -> Self {
        Self {
            primary_biome: Biome::default(),
            accent_elements: vec![],
            time_of_day: default_time_of_day(),
        }
    }
}

fn default_time_of_day() -> f32 {
    0.6
}

/// Biome presets.
#[derive(Debug, Clone, Copy, Default, PartialEq, Eq, Serialize, Deserialize, Reflect)]
#[serde(rename_all = "snake_case")]
pub enum Biome {
    #[default]
    TemperateForest,
    Desert,
    Tundra,
    Tropical,
    Swamp,
    Volcanic,
    Arctic,
    Savanna,
}

// ---------------------------------------------------------------------------
// Bevy components
// ---------------------------------------------------------------------------

/// Marker component for entities generated by the blockout pipeline.
#[derive(Component, Reflect)]
#[reflect(Component)]
pub struct BlockoutGenerated {
    /// Which region this entity belongs to.
    pub region_id: String,
    /// Generation pass: "terrain", "volume", "path", "hero", "medium", "decorative".
    pub pass: String,
}

/// Debug volume for visualizing blockout regions.
#[derive(Component, Reflect)]
#[reflect(Component)]
pub struct BlockoutVolume {
    /// Region this volume represents.
    pub region_id: String,
    /// Role (for hero slots: "landmark", "entrance", etc.).
    pub role: String,
    /// Content hint.
    pub hint: String,
}

/// Resource storing the current blockout specification.
#[derive(Resource, Debug, Clone)]
pub struct CurrentBlockout {
    pub spec: BlockoutSpec,
}

// ---------------------------------------------------------------------------
// Prompt → BlockoutSpec heuristic mapping
// ---------------------------------------------------------------------------

impl BlockoutSpec {
    /// Generate a reasonable default BlockoutSpec from a text prompt and world size.
    ///
    /// Uses keyword matching to select terrain type, layout style, biome, and
    /// region structure. The LLM can review and adjust before applying.
    pub fn from_prompt(prompt: &str, size: [f32; 2], seed: Option<u32>) -> Self {
        let lower = prompt.to_lowercase();

        // Terrain type inference
        let terrain_type = if lower.contains("flat") || lower.contains("plain") {
            TerrainType::Flat
        } else if lower.contains("mountain") || lower.contains("peak") || lower.contains("alpine") {
            TerrainType::Mountains
        } else if lower.contains("canyon") || lower.contains("gorge") || lower.contains("ravine") {
            TerrainType::Canyon
        } else if lower.contains("island") || lower.contains("archipelago") {
            TerrainType::Island
        } else if lower.contains("plateau") || lower.contains("mesa") {
            TerrainType::Plateau
        } else {
            TerrainType::Hills
        };

        // Biome inference
        let biome = if lower.contains("desert") || lower.contains("sand") || lower.contains("arid")
        {
            Biome::Desert
        } else if lower.contains("snow") || lower.contains("arctic") || lower.contains("frozen") {
            Biome::Arctic
        } else if lower.contains("tundra") {
            Biome::Tundra
        } else if lower.contains("tropical") || lower.contains("jungle") {
            Biome::Tropical
        } else if lower.contains("swamp") || lower.contains("marsh") || lower.contains("bog") {
            Biome::Swamp
        } else if lower.contains("volcano") || lower.contains("lava") {
            Biome::Volcanic
        } else if lower.contains("savanna") || lower.contains("grassland") {
            Biome::Savanna
        } else {
            Biome::TemperateForest
        };

        // Layout style inference
        let (layout_style, regularity) =
            if lower.contains("village") || lower.contains("town") || lower.contains("city") {
                (LayoutStyle::Structured, 0.6)
            } else if lower.contains("arena") || lower.contains("temple") || lower.contains("ring")
            {
                (LayoutStyle::Radial, 0.7)
            } else if lower.contains("farm") || lower.contains("grid") {
                (LayoutStyle::Grid, 0.8)
            } else {
                (LayoutStyle::Organic, 0.3)
            };

        // Density inference
        let density =
            if lower.contains("dense") || lower.contains("thick") || lower.contains("crowded") {
                0.8
            } else if lower.contains("sparse") || lower.contains("empty") || lower.contains("open")
            {
                0.2
            } else {
                0.5
            };

        // Time of day inference
        let time_of_day = if lower.contains("night") || lower.contains("midnight") {
            0.0
        } else if lower.contains("dawn") || lower.contains("sunrise") {
            0.25
        } else if lower.contains("sunset") || lower.contains("dusk") || lower.contains("evening") {
            0.75
        } else {
            0.6 // default: afternoon
        };

        // Verticality from terrain type
        let verticality = match terrain_type {
            TerrainType::Flat => 0.05,
            TerrainType::Hills => 0.4,
            TerrainType::Mountains => 0.9,
            TerrainType::Canyon => 0.7,
            TerrainType::Island => 0.5,
            TerrainType::Plateau => 0.3,
        };

        // Generate default regions from keywords
        let regions = Self::infer_regions(&lower, size, layout_style, density);

        // Generate paths between adjacent regions
        let paths = Self::infer_paths(&regions);

        BlockoutSpec {
            terrain: BlockoutTerrain {
                terrain_type,
                verticality,
                roughness: 0.4,
                base_height: 0.0,
                noise_seed: seed,
            },
            layout: LayoutParams {
                style: layout_style,
                density,
                regularity,
            },
            regions,
            paths,
            palette: WorldPalette {
                primary_biome: biome,
                accent_elements: Self::infer_accents(&lower),
                time_of_day,
            },
        }
    }

    /// Infer regions from prompt keywords.
    fn infer_regions(
        lower: &str,
        size: [f32; 2],
        default_style: LayoutStyle,
        density: f32,
    ) -> Vec<RegionDef> {
        let mut regions = Vec::new();
        let half_x = size[0] / 2.0;
        let half_z = size[1] / 2.0;

        // Settlement regions
        if lower.contains("village") || lower.contains("town") || lower.contains("settlement") {
            regions.push(RegionDef {
                id: "village_center".to_string(),
                bounds: RegionBounds {
                    center: [0.0, 0.0],
                    size: [size[0] * 0.3, size[1] * 0.3],
                },
                region_type: LayoutStyle::Structured,
                density: 0.7,
                walkable: true,
                hero_slots: vec![HeroSlot {
                    position: [0.0, 0.0, 0.0],
                    size: [8.0, 6.0, 8.0],
                    role: "landmark".to_string(),
                    hint: "central building".to_string(),
                }],
                medium_density: 0.6,
                decorative_density: 0.4,
            });
        }

        // Forest regions
        if lower.contains("forest") || lower.contains("woods") || lower.contains("trees") {
            let cx = if regions.is_empty() {
                0.0
            } else {
                half_x * 0.6
            };
            regions.push(RegionDef {
                id: "forest".to_string(),
                bounds: RegionBounds {
                    center: [cx, 0.0],
                    size: [size[0] * 0.4, size[1] * 0.5],
                },
                region_type: LayoutStyle::Organic,
                density: 0.8,
                walkable: true,
                hero_slots: vec![],
                medium_density: 0.8,
                decorative_density: 0.9,
            });
        }

        // Lake/water area
        if lower.contains("lake") || lower.contains("pond") || lower.contains("river") {
            let cx = if regions.len() > 1 {
                -half_x * 0.4
            } else if regions.len() == 1 {
                half_x * 0.5
            } else {
                0.0
            };
            regions.push(RegionDef {
                id: "water_area".to_string(),
                bounds: RegionBounds {
                    center: [cx, half_z * 0.3],
                    size: [size[0] * 0.25, size[1] * 0.25],
                },
                region_type: LayoutStyle::Organic,
                density: 0.1,
                walkable: false,
                hero_slots: vec![],
                medium_density: 0.1,
                decorative_density: 0.2,
            });
        }

        // If no regions inferred, create a single default region
        if regions.is_empty() {
            regions.push(RegionDef {
                id: "main".to_string(),
                bounds: RegionBounds {
                    center: [0.0, 0.0],
                    size: [size[0] * 0.6, size[1] * 0.6],
                },
                region_type: default_style,
                density,
                walkable: true,
                hero_slots: vec![],
                medium_density: density,
                decorative_density: density * 0.6,
            });
        }

        regions
    }

    /// Infer paths between adjacent regions.
    fn infer_paths(regions: &[RegionDef]) -> Vec<PathConnection> {
        let mut paths = Vec::new();
        // Connect each region to the next (simple chain)
        for i in 0..regions.len().saturating_sub(1) {
            paths.push(PathConnection {
                from: regions[i].id.clone(),
                to: regions[i + 1].id.clone(),
                width: 3.0,
                style: PathStyle::Dirt,
            });
        }
        paths
    }

    /// Infer accent elements from prompt.
    fn infer_accents(lower: &str) -> Vec<String> {
        let mut accents = Vec::new();
        let keywords = [
            "stone",
            "flowers",
            "mushrooms",
            "rocks",
            "crystals",
            "ruins",
            "fences",
            "lanterns",
            "barrels",
            "crates",
        ];
        for &kw in &keywords {
            if lower.contains(kw) {
                accents.push(kw.to_string());
            }
        }
        if accents.is_empty() {
            // Sensible defaults
            accents.push("stone".to_string());
            accents.push("flowers".to_string());
        }
        accents
    }

    /// Validate the spec for consistency.
    pub fn validate(&self) -> Result<(), String> {
        // Check region IDs are unique
        let mut ids = std::collections::HashSet::new();
        for region in &self.regions {
            if !ids.insert(&region.id) {
                return Err(format!("Duplicate region ID: '{}'", region.id));
            }
        }

        // Check path references
        for path in &self.paths {
            if !ids.contains(&path.from) {
                return Err(format!("Path references unknown region: '{}'", path.from));
            }
            if !ids.contains(&path.to) {
                return Err(format!("Path references unknown region: '{}'", path.to));
            }
        }

        // Check value ranges
        for region in &self.regions {
            if region.density < 0.0 || region.density > 1.0 {
                return Err(format!(
                    "Region '{}' density out of range: {}",
                    region.id, region.density
                ));
            }
        }

        Ok(())
    }
}

// ---------------------------------------------------------------------------
// Tests
// ---------------------------------------------------------------------------

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_blockout_spec_from_prompt_village() {
        let spec =
            BlockoutSpec::from_prompt("a medieval village with a forest", [50.0, 50.0], None);
        assert_eq!(spec.terrain.terrain_type, TerrainType::Hills);
        assert_eq!(spec.layout.style, LayoutStyle::Structured);
        assert_eq!(spec.palette.primary_biome, Biome::TemperateForest);
        assert!(spec.regions.len() >= 2);
        assert!(spec.regions.iter().any(|r| r.id == "village_center"));
        assert!(spec.regions.iter().any(|r| r.id == "forest"));
        assert!(!spec.paths.is_empty());
    }

    #[test]
    fn test_blockout_spec_from_prompt_desert() {
        let spec =
            BlockoutSpec::from_prompt("a sparse desert with sand dunes", [100.0, 100.0], Some(42));
        assert_eq!(spec.terrain.terrain_type, TerrainType::Hills);
        assert_eq!(spec.palette.primary_biome, Biome::Desert);
        assert_eq!(spec.terrain.noise_seed, Some(42));
    }

    #[test]
    fn test_blockout_spec_from_prompt_mountain() {
        let spec = BlockoutSpec::from_prompt("mountain peaks at night", [80.0, 80.0], None);
        assert_eq!(spec.terrain.terrain_type, TerrainType::Mountains);
        assert!(spec.terrain.verticality > 0.8);
        assert!(spec.palette.time_of_day < 0.1);
    }

    #[test]
    fn test_blockout_spec_from_prompt_default() {
        let spec = BlockoutSpec::from_prompt("something interesting", [50.0, 50.0], None);
        assert_eq!(spec.terrain.terrain_type, TerrainType::Hills);
        assert_eq!(spec.layout.style, LayoutStyle::Organic);
        assert!(!spec.regions.is_empty());
    }

    #[test]
    fn test_blockout_spec_validate_ok() {
        let spec = BlockoutSpec::from_prompt("a village", [50.0, 50.0], None);
        assert!(spec.validate().is_ok());
    }

    #[test]
    fn test_blockout_spec_validate_duplicate_region() {
        let mut spec = BlockoutSpec::from_prompt("a village", [50.0, 50.0], None);
        if let Some(first) = spec.regions.first() {
            spec.regions.push(first.clone());
        }
        assert!(spec.validate().is_err());
    }

    #[test]
    fn test_blockout_spec_validate_bad_path() {
        let mut spec = BlockoutSpec::from_prompt("a village", [50.0, 50.0], None);
        spec.paths.push(PathConnection {
            from: "nonexistent".to_string(),
            to: "also_nonexistent".to_string(),
            width: 3.0,
            style: PathStyle::Dirt,
        });
        assert!(spec.validate().is_err());
    }

    #[test]
    fn test_blockout_spec_serde_roundtrip() {
        let spec =
            BlockoutSpec::from_prompt("a village with forest and lake", [50.0, 50.0], Some(123));
        let json = serde_json::to_string_pretty(&spec).unwrap();
        let parsed: BlockoutSpec = serde_json::from_str(&json).unwrap();
        assert_eq!(parsed.terrain.terrain_type, spec.terrain.terrain_type);
        assert_eq!(parsed.regions.len(), spec.regions.len());
        assert_eq!(parsed.paths.len(), spec.paths.len());
    }

    #[test]
    fn test_terrain_params_conversion() {
        let terrain = BlockoutTerrain {
            terrain_type: TerrainType::Mountains,
            verticality: 0.9,
            roughness: 0.6,
            ..Default::default()
        };
        let params = terrain.to_terrain_params(Vec2::new(100.0, 100.0));
        assert!(params.height_scale > 50.0); // Mountains * 0.9 verticality
        assert_eq!(params.noise_octaves, 6);
    }

    #[test]
    fn test_terrain_type_all_variants() {
        let types = [
            TerrainType::Flat,
            TerrainType::Hills,
            TerrainType::Mountains,
            TerrainType::Canyon,
            TerrainType::Island,
            TerrainType::Plateau,
        ];
        for t in types {
            let terrain = BlockoutTerrain {
                terrain_type: t,
                ..Default::default()
            };
            let params = terrain.to_terrain_params(Vec2::splat(50.0));
            assert!(params.height_scale > 0.0);
        }
    }

    #[test]
    fn test_biome_all_variants() {
        let biomes = [
            Biome::TemperateForest,
            Biome::Desert,
            Biome::Tundra,
            Biome::Tropical,
            Biome::Swamp,
            Biome::Volcanic,
            Biome::Arctic,
            Biome::Savanna,
        ];
        for b in biomes {
            let json = serde_json::to_string(&b).unwrap();
            let parsed: Biome = serde_json::from_str(&json).unwrap();
            assert_eq!(parsed, b);
        }
    }

    #[test]
    fn test_layout_style_all_variants() {
        let styles = [
            LayoutStyle::Structured,
            LayoutStyle::Organic,
            LayoutStyle::Radial,
            LayoutStyle::Grid,
        ];
        for s in styles {
            let json = serde_json::to_string(&s).unwrap();
            let parsed: LayoutStyle = serde_json::from_str(&json).unwrap();
            assert_eq!(parsed, s);
        }
    }

    #[test]
    fn test_path_style_all_variants() {
        let styles = [
            PathStyle::Dirt,
            PathStyle::Stone,
            PathStyle::Cobblestone,
            PathStyle::Grass,
            PathStyle::Sand,
        ];
        for s in styles {
            let json = serde_json::to_string(&s).unwrap();
            let parsed: PathStyle = serde_json::from_str(&json).unwrap();
            assert_eq!(parsed, s);
        }
    }

    #[test]
    fn test_infer_accents_with_keywords() {
        let accents = BlockoutSpec::infer_accents("a village with stone walls and flowers");
        assert!(accents.contains(&"stone".to_string()));
        assert!(accents.contains(&"flowers".to_string()));
    }

    #[test]
    fn test_infer_accents_default() {
        let accents = BlockoutSpec::infer_accents("something generic");
        assert!(!accents.is_empty());
    }

    #[test]
    fn test_island_terrain_type() {
        let spec = BlockoutSpec::from_prompt("a tropical island", [60.0, 60.0], None);
        assert_eq!(spec.terrain.terrain_type, TerrainType::Island);
        assert_eq!(spec.palette.primary_biome, Biome::Tropical);
    }

    #[test]
    fn test_arena_radial_layout() {
        let spec = BlockoutSpec::from_prompt("a gladiator arena", [40.0, 40.0], None);
        assert_eq!(spec.layout.style, LayoutStyle::Radial);
    }
}
